Submit: #include <iostream>
int factorial(int n) {
    int res = 1;
    for (int i=1; i<=n; i++) {
        res = res * i // Szintaktikai hiba: hiányzó pontosvessző
    }
    return res;
}
int main() {
    std::cout << factorial(5) << std::endl;
    return 0;
}

Submit: #include <iostream>
int factorial(int n) {
    if (n <= 1) return 1;
    int res = 1;
    for (int i = 2; i <= n; ++i) {
        res *= i;
    }
    return res;
}
int main() {
    std::cout << factorial(5) << std::endl;
    return 0;
}
